patches.new_code:
function cleanTextForSpeech(text) {
            if (!text) return '';
            let cleaned = text;
            // [수정] TTS로 읽기 전, 그리고 '원본' 문장으로 사용되기 전에 모든 문장 부호와 특수 기호를 제거합니다.
            cleaned = cleaned.replace(/[.,!?'"‘’”“]/g, ' '); // 마침표, 쉼표, 따옴표 등 제거
            cleaned = cleaned.replace(/\[.*?\]/g, ' ');      // [대괄호] 내용 제거
            cleaned = cleaned.replace(/\(.*?\)/g, ' ');      // (소괄호) 내용 제거
            cleaned = cleaned.replace(/[-~*♪♫]/g, ' ');      // 특수기호 제거
            cleaned = cleaned.replace(/^[가-힣A-Za-z0-9\s]+:/gm, ' '); // "이름:" 같은 형식 제거
            return cleaned.replace(/\s+/g, ' ').trim();     // 여러 공백을 하나로 합치고 앞뒤 공백 제거
        }
